var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"마왕을 앞에 두고도 여유롭군요, 현자여.","JPN":"魔王を前にして余裕がありますね、賢者。","ENG":"You seem very calm with a Demon Lord in front of you, Sage.","TWN":"面對魔王你還遊刃有餘呢，智者。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"싸우러 온 건 아닙니다. 싸움이라면 머지않아 질릴만큼 하게 될 테니까요.","JPN":"戦うつもりで来たのではありません。戦いなら遠からず嫌というほどすることになりますから。","ENG":"I am not here to fight. I will have more than enough of that soon.","TWN":"我不是來打架的，要打的話，之後有的是機會。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"단지…… 오늘은 당신에게 조언을 구하고 싶어 찾아왔습니다.","JPN":"ただ……今日はあなたから助言をいただきたくて来ました。","ENG":"It's just that... I wanted to ask for your advice.","TWN":"今天……我是來向你討教的。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"물론, 이제와서 답을 얻는다고 해도, 돌이키기엔 너무 멀리 왔을지도 모르겠지만.","JPN":"もちろん、いまさら答えを得ても、引き返すには遅すぎるのかもしれませんが。","ENG":"Of course, even if I do get an answer, I might be far past the point of no return.","TWN":"當然，現在就算得到答案，想回頭可能也已經太遲。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"당신도 아시다시피, 저는 가짜 구원자. 세계를 구하지 못한 실패자에 불과하겠죠.","JPN":"あなたもご存じのように、僕は偽の救世主。世界を救えなかった失敗者に過ぎません。","ENG":"As you know well, I am a False Savior. I am nothing but a failure who couldn't save my world.","TWN":"如你所知，我是假的救世主，我不過是沒能拯救世界的失敗者。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"하지만…… 그건 당신도 같은 처지일 겁니다.","JPN":"でも……それはあなたも同じです。","ENG":"But... that'll be the same for you.","TWN":"但是……你應該和我處境相仿吧？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"이걸로 대체 몇 번째죠? 세계를 구한다는 이유로 이렇게 허망하고 부질없는 싸움을 계속해온 것이?","JPN":"いったいこれで何度目なのでしょうか。世界を救うという名目でこうして虚しく意味のない戦いを続けてきたのが？","ENG":"How many times have you done this? This pointless, meaningless game of attempting to save the world?","TWN":"這到底已經是第幾次？以拯救世界為藉口，繼續這種毫無意義的戰鬥？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 부디 대답해주세요, 현자여.","JPN":"ならば、どうかお答えください。賢者。","ENG":"Please answer, Sage.","TWN":"請你務必回答我，智者。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"수많은 사람들의 희생 위에 서있으면서…… 당신은 어떻게 그렇게 태연할 수 있죠?","JPN":"多くの人々の犠牲の上に立ちながら……あなたはどうしてそんなに平気でいられるのですか？","ENG":"How can you stay so calm... when you are standing above countless sacrifices and deaths?","TWN":"站在無數人的犧牲之上……你是如何做到如此的泰然自若？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"수많은 세계의 인과를 뒤틀어가면서…… 당신은 어떻게 그렇게 확신에 차 있을 수 있죠?","JPN":"数多の世界の因果を捻じ曲げながら……あなたはどうしてそんなに確信に満ちていられるのですか？","ENG":"How can you be so sure... when you've been twisting countless causalities?","TWN":"為何你還能那麼堅定……當你的一個決定將會扭曲無數世界的因果？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"대체 무엇이…… 당신을 그렇게 포기하지 않게 만드는 겁니까!","JPN":"いったいどうして……そんなに諦めずにいられるのですか！","ENG":"What makes you... never give up?!","TWN":"究竟是什麼……讓你如此堅定！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"만약 당신의 싸움 끝에도 구원이 없다면…… 당신은 대체 어쩔 작정이기에…….","JPN":"もしあなたの戦いの先にも救いがないとしたら……あなたはいったいどうするつもりで……","ENG":"If there is no salvation waiting for you at the end... what do you plan to do...?","TWN":"如果你戰鬥的盡頭也沒有救贖……那究竟想要的是什麼呢……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};